import AppKit
import SwiftUI

struct ProviderIcon: View {
    let provider: QuotaProviderID

    var body: some View {
        Image(nsImage: ProviderIconAsset.image(for: provider))
            .resizable()
            .scaledToFit()
            .foregroundStyle(.primary)
            .frame(width: 12, height: 12)
            .accessibilityHidden(true)
    }
}

enum ProviderIconAsset {
    static let claudeSourceFileName = "claude.svg"
    static let codexSourceFileName = "chatgpt.svg"

    static func data(for provider: QuotaProviderID) -> Data? {
        Data(
            base64Encoded: provider == .claude ? claudeSVGBase64 : chatGPTSVGBase64,
            options: .ignoreUnknownCharacters
        )
    }

    static func image(for provider: QuotaProviderID) -> NSImage {
        guard let data = data(for: provider), let image = NSImage(data: data) else {
            return NSImage()
        }
        image.isTemplate = provider == .codex
        return image
    }

    private static let claudeSVGBase64 = ""

    private static let chatGPTSVGBase64 = ""
}
